  ('pravila_saobracaja_0522', 'pravila_saobracaja', 'На саобраћајницама ван уличних паркиралишта које повезују паркинг просторе и стамбене зграде са другим саобраћајницама:', 'multipleChoice', NULL, 2, 522),
