  ('pravila_saobracaja_0790', 'pravila_saobracaja', 'Зона "30" је:', 'multipleChoice', NULL, 2, 790),
  ('pravila_saobracaja_0791', 'pravila_saobracaja', 'Део пута, улице или насеља у којој је брзина кретања возила ограничена до 30 km/h је:', 'multipleChoice', NULL, 1, 791),
  ('pravila_saobracaja_0792', 'pravila_saobracaja', 'Брзина кретања возила насељу, на делу пута улице у непосредној близини школе („Зона школе“), је ограничена до:', 'multipleChoice', NULL, 2, 792),
  ('pravila_saobracaja_0793', 'pravila_saobracaja', 'Брзина кретања возила ван насеља, на делу пута или улице у непосредној близини школе („Зона школе“), је ограничена до:', 'multipleChoice', NULL, 2, 793),
  ('pravila_saobracaja_0794', 'pravila_saobracaja', 'Возач мора искључити мотор возила којим управља када прекид кретања у тунелу траје дуже од:', 'multipleChoice', NULL, 2, 794),
  ('pravila_saobracaja_0795', 'pravila_saobracaja', 'Возач мора искључити мотор возила којим управља:', 'multipleChoice', NULL, 2, 795),
  ('pravila_saobracaja_0796', 'pravila_saobracaja', 'Возач мора искључити мотор возила којим управља:', 'multipleChoice', NULL, 2, 796),
  ('pravila_saobracaja_0797', 'pravila_saobracaja', 'Испуштање, односно одлагање материје и отпада, којим се угрожава живот и здравље људи, животиња, биљака или загађује животна средина:', 'multipleChoice', NULL, 2, 797),
  ('signalizacija_0001', 'signalizacija', 'За време управљања возилом у саобраћају на путу, возачи су дужни да:', 'multipleChoice', NULL, 2, 1),
  ('signalizacija_0002', 'signalizacija', 'Саобраћајни знакови:', 'multipleChoice', NULL, 2, 2),
  ('signalizacija_0003', 'signalizacija', 'Саобраћајни знакови који су изведени са изменљивим садржајем порука:', 'multipleChoice', NULL, 2, 3) ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, category_id, text, type, image_name, difficulty, order_index) VALUES
  ('signalizacija_0004', 'signalizacija', 'Саобраћајни знакови се постављају:', 'multipleChoice', NULL, 2, 4),
  ('signalizacija_0005', 'signalizacija', 'Саобраћајни знакови се постављају са:', 'multipleChoice', NULL, 1, 5),
  ('signalizacija_0006', 'signalizacija', 'Постављање, уклањање и измена значења саобраћајне сигнализације као и опреме пута, учесницима у саобраћају:', 'multipleChoice', NULL, 1, 6),
  ('signalizacija_0007', 'signalizacija', 'других сличних предмета којима се заклања или умањује уочљивост постављене саобраћајне сигнализације, учесницима у саобраћају:', 'multipleChoice', NULL, 1, 7),
  ('signalizacija_0008', 'signalizacija', 'личе на саобраћајну сигнализацију или заслепљују учеснике у саобраћају или одвраћају њихову пажњу у мери која може бити опасна за безбедност саобраћаја, учесницима у саобраћају:', 'multipleChoice', NULL, 2, 8),
  ('signalizacija_0009', 'signalizacija', 'Саобраћајни знакови су:', 'multipleChoice', NULL, 2, 9),
  ('signalizacija_0010', 'signalizacija', 'Саобраћајни знакови се изводе тако да се садржај њихових порука:', 'multipleChoice', NULL, 2, 10),
  ('signalizacija_0011', 'signalizacija', 'Саобраћајни знакови којима се учесницима у саобраћају на путу стављају до знања забране, ограничења и обавезе којих се морају придржавати су:', 'multipleChoice', NULL, 2, 11),
  ('signalizacija_0012', 'signalizacija', 'Саобраћајни знакови који учеснике саобраћају упозоравају на опасност која им прети на одређеном месту, односно делу пута и обавештавају о природи те опасности су:', 'multipleChoice', NULL, 2, 12),
  ('signalizacija_0013', 'signalizacija', 'Саобраћајни знакови који учесницима у саобраћају пружају потребна обавештења о путу којим се крећу и друга обавештења која им могу бити корисна су:', 'multipleChoice', NULL, 2, 13),
  ('signalizacija_0014', 'signalizacija', 'Саобраћајни знакови који су изведени са изменљивим садржајем порука:', 'multipleChoice', NULL, 2, 14),
  ('signalizacija_0015', 'signalizacija', 'Знакови опасности, по правилу, се постављају:', 'multipleChoice', NULL, 3, 15),
  ('signalizacija_0016', 'signalizacija', 'Знак опасности који је постављен на путу ван насеља на удаљености мањој од 150 m или већој од 250 m испред опасног места на путу:', 'multipleChoice', NULL, 3, 16),
