  ('vozila_0077', 'vozila', 'Истоветни светлосни и светлосно сигнални уређаји који су удвојени на моторном возилу на три или више точкова:', 'multipleChoice', NULL, 2, 77),
  ('vozila_0078', 'vozila', 'Под уређајима за осветљавање пута на моторним возилима, од набројаних, подразумевају се:', 'multipleChoice', NULL, 2, 78),
  ('vozila_0079', 'vozila', 'Под уређајима за осветљавање пута на моторним возилима, од набројаног, подразумевају се:', 'multipleChoice', NULL, 2, 79) ON CONFLICT (id) DO NOTHING;
