  ('vozaci_0090', 'vozaci', 'Возач возила којим се превозе опасне материје, односно врши ванредни превоз, када управља возилом у саобраћају на путу:', 'multipleChoice', NULL, 3, 90),
  ('vozaci_0091', 'vozaci', 'Када учествује у саобраћају на путу, не сме да има алкохола у организму возач:', 'multipleChoice', NULL, 3, 91),
  ('vozaci_0092', 'vozaci', 'Возач возила категорије АМ, када управља возилом у саобраћају на путу:', 'multipleChoice', NULL, 3, 92),
