  ('vozaci_0106', 'vozaci', 'Лице које се затекне или наиђе на место саобраћајне незгоде у којој има повређених лица:', 'multipleChoice', NULL, 1, 106),
  ('vozaci_0107', 'vozaci', 'троугао на безбедном растојању, обавести полицију и/или службу хитне помоћи и предузме друге расположиве мере како би упозорио остале учеснике у саобраћају о постојању незгоде:', 'multipleChoice', NULL, 2, 107),
