  ('vozaci_0109', 'vozaci', 'Возач који је учествовао у саобраћајној незгоди у којој је неко лице задобило телесне повреде, односно погинуло, или је настала велика материјална штета дужан је да:', 'multipleChoice', NULL, 2, 109),
  ('vozaci_0110', 'vozaci', 'Возач који је учествовао у саобраћајној незгоди у којој је неко лице задобило телесне повреде, односно погинуло, или је настала велика материјална штета:', 'multipleChoice', NULL, 1, 110),
  ('vozaci_0111', 'vozaci', 'је неко лице задобило телесне повреде, односно погинуло, или је настала велика материјална штета дужан је да:', 'multipleChoice', NULL, 1, 111),
  ('vozaci_0112', 'vozaci', 'је неко лице задобило телесне повреде, односно погинуло, или је настала велика материјална штета:', 'multipleChoice', NULL, 2, 112),
  ('vozaci_0113', 'vozaci', 'У саобраћајној незгоди у којој је настала мања материјална штета, било који учесник саобраћајне незгоде или лице које је претрпело материјалну штету:', 'multipleChoice', NULL, 1, 113),
  ('vozaci_0114', 'vozaci', 'материјалну штету, у саобраћајној незгоди у којој је настала мања материјална штета, захтевао вршење увиђаја остали учесници:', 'multipleChoice', NULL, 2, 114) ON CONFLICT (id) DO NOTHING;
INSERT INTO questions (id, category_id, text, type, image_name, difficulty, order_index) VALUES
  ('vozaci_0115', 'vozaci', 'Возач који је учествовао у саобраћајној незгоди у којој је настала само мања материјална штета:', 'multipleChoice', NULL, 1, 115),
  ('vozaci_0116', 'vozaci', 'присуства алкохола, односно психоактивних супстанци у организму учесника саобраћајне незгоде у којој има погинулих, односно повређених лица:', 'multipleChoice', NULL, 1, 116),
  ('vozaci_0117', 'vozaci', 'Возач који је учествовао у саобраћајној незгоди у којој је настала само мања материјална штета:', 'multipleChoice', NULL, 2, 117),
  ('vozaci_0118', 'vozaci', 'Возач који је учествовао у саобраћајној незгоди у којој је настала само мања материјална штета::', 'multipleChoice', NULL, 1, 118),
  ('vozaci_0119', 'vozaci', 'мања материјална штета на другом возилу, због одсутности возача другог возила, није у могућности да пружи личне податке и податке о осигурању возила, дужан је да:', 'multipleChoice', NULL, 2, 119),
  ('vozaci_0120', 'vozaci', 'Одузете регистарске таблице са возила које је учествовало у саобраћајној незгоди враћају се власнику, односно кориснику возила:', 'multipleChoice', NULL, 2, 120),
  ('vozaci_0121', 'vozaci', 'Приликом вршења увиђаја саобраћајне незгоде у којој нема погинулих, односно повређених лица, испитивање возача на присуство алкохола, односно психоактивних супстанци, помоћу одговарајућих средстава (алкометар, дрога тест и др.):', 'multipleChoice', NULL, 2, 121),
  ('vozaci_0122', 'vozaci', 'Меру искључења и одузимања регистарских таблица возила која су учествовала у саобраћајној незгоди полицијски службеник примењује:', 'multipleChoice', NULL, 2, 122),
  ('vozaci_0123', 'vozaci', 'Након обављеног увиђаја саобраћајне незгоде, возач, односно власник возила, дужан је да:', 'multipleChoice', NULL, 2, 123),
  ('vozaci_0124', 'vozaci', 'Након саобраћајне незгоде са мањом материјалном штетом учесници у саобраћајној незгоди:', 'multipleChoice', NULL, 1, 124),
