  ('vozaci_0199', 'vozaci', 'нестала (изгубљена или украдена), возач је дужан да на дневном испису са дигиталног тахографа, по завршетку времена управљања, евидентира:', 'multipleChoice', NULL, 1, 199),
  ('vozaci_0200', 'vozaci', 'Возач може картицу возача извадити из дигиталног тахографа:', 'multipleChoice', NULL, 1, 200),
  ('vozaci_0201', 'vozaci', 'дигитални тахограф сме да након тога управља возилом у које је уграђен аналогни тахограф, до истека дневног времена управљања?', 'multipleChoice', NULL, 1, 201),
