  ('posledice_0062', 'posledice', 'Возач теретног возила или скупа возила чија је највећа дозвољена маса већа од 3.500 kg, који не искористи дневни одмор на прописан начин, казниће се:', 'multipleChoice', NULL, 2, 62),
  ('posledice_0063', 'posledice', 'Возач аутобуса који благовремено не започне са коришћењем недељног одмора, казниће се:', 'multipleChoice', NULL, 2, 63),
  ('posledice_0064', 'posledice', 'Возач теретног возила или скупа возила чија је највећа дозвољена маса већа од 3.500 kg, који благовремено не започне са коришћењем недељног одмора, казниће се', 'multipleChoice', NULL, 1, 64),
  ('posledice_0065', 'posledice', 'Возач који се у ситуацији приказаној на слици, не заустави иза возила за организовани превоз деце, казниће се:', 'multipleChoice', 'posledice_0065.png', 1, 65),
