  ('posledice_0086', 'posledice', 'Возач аутобуса који започне кретање пре него што путници безбедно не уђу, односно изађу из возила и док врата не буду затворена, казниће се:', 'multipleChoice', NULL, 1, 86),
  ('posledice_0087', 'posledice', 'саобраћајни знак у облику зелене стрелице (условни знак), не пропусти пешака који прелази преко коловоза, казниће се:', 'multipleChoice', NULL, 1, 87),
  ('posledice_0088', 'posledice', 'саобраћајни знак у облику зелене стрелице (условни знак), не пропусти возило које се креће по путу на који улази, казниће се:', 'multipleChoice', NULL, 2, 88),
