  ('posledice_0091', 'posledice', 'Возач који се затекне или наиђе на место саобраћајне незгоде у којој има повређених лица а не обавести полицију и/или службу хитне медицинске помоћи, казниће се:', 'multipleChoice', NULL, 2, 91),
  ('posledice_0092', 'posledice', 'Возач који након истека пробне возачке дозволе управља возилом у саобраћају пре него што му је издата возачка дозвола, казниће се:', 'multipleChoice', NULL, 2, 92),
  ('posledice_0093', 'posledice', 'Возач који управља возилом када је његовој возачкој дозволи истекао рок важења највише шест месеци, казниће се:', 'multipleChoice', NULL, 2, 93),
  ('posledice_0094', 'posledice', 'Возач коме је издата пробна возачка дозвола, који управља возилом у периоду од 23:00 до 05:00 сати, казниће се:', 'multipleChoice', NULL, 2, 94),
  ('posledice_0095', 'posledice', 'Возач који након промене пребивалишта не пријави ту промену у прописаном року надлежном органу, казниће се:', 'multipleChoice', NULL, 2, 95),
