  ('posledice_0097', 'posledice', 'Кандидат за возача који управља возилом током практичне обуке у стању средње алкохолисаности, казниће се:', 'multipleChoice', NULL, 2, 97),
  ('posledice_0098', 'posledice', 'Возач који управља возилом којем је неисправан уграђени тахограф, казниће се:', 'multipleChoice', NULL, 2, 98),
  ('posledice_0099', 'posledice', 'Возач који управља возилом који уграђени тахограф не користи на прoписан начин, казниће се:', 'multipleChoice', NULL, 2, 99),
  ('posledice_0100', 'posledice', 'Возач који управља возилом које је технички неисправно у погледу уређаја за заустављање, казниће се:', 'multipleChoice', NULL, 2, 100),
  ('posledice_0101', 'posledice', 'Власник неисправног возила у погледу уређаја за заустављање, којим у саобраћају на путу управља друго лице, казниће се:', 'multipleChoice', NULL, 2, 101),
  ('posledice_0102', 'posledice', 'Возач преправљеног возила који учествује у саобраћају пре него што је надлежни орган утврдио да возило испуњава прописане услове, казниће се:', 'multipleChoice', NULL, 2, 102),
  ('posledice_0103', 'posledice', 'Возач који након истека рока од шест месеци од дана почетка важења регистрационе налепнице, управља возилом пре него што је на редовном шестомесечном техничком прегледу утврђено да је возило технички исправно, казниће се:', 'multipleChoice', NULL, 2, 103),
  ('posledice_0104', 'posledice', 'Возач који управља возилом, након истека рока важења регистрационе налепнице, казниће се:', 'multipleChoice', NULL, 1, 104),
  ('posledice_0105', 'posledice', 'захтев за издавање нове регистрационе налепнице, који у прописаном року не врати регистарске таблице органу који је исте издао, казниће се:', 'multipleChoice', NULL, 2, 105),
  ('posledice_0106', 'posledice', 'Власник возила који у прописаном року не пријави промену било ког податка који се уписује у саобраћајну дозволу, казниће се:', 'multipleChoice', NULL, 2, 106),
  ('posledice_0107', 'posledice', 'Власник возила којим је учињен прекршај у случају када возач који је управљао возилом приликом извршења прекршаја није идентификован:', 'multipleChoice', NULL, 2, 107),
  ('posledice_0108', 'posledice', 'Власник возила којим је учињен прекршај у случају када возач који је управљао возилом приликом извршења прекршаја није идентификован, казниће се:', 'multipleChoice', NULL, 1, 108),
  ('posledice_0109', 'posledice', 'Возач који управља аутобусом којим се врши организован превоз деце који није обележен посебним знаком, казниће се:', 'multipleChoice', NULL, 2, 109),
  ('posledice_0110', 'posledice', 'Возач који у насељу не омогући укључивање у саобраћај аутобусу који се прописно укључује у саобраћај са стајалишта, казниће се:', 'multipleChoice', NULL, 2, 110),
  ('posledice_0111', 'posledice', 'Возач који за време вожње користи мобилни телефон на непрописан начин, казниће се:', 'multipleChoice', NULL, 2, 111),
  ('posledice_0112', 'posledice', 'Возач возила у којем су уграђени сигурносни појасеви, који у саобраћају на путу не користи сигурносни појас на прописан начин, казниће се:', 'multipleChoice', NULL, 2, 112),
  ('posledice_0113', 'posledice', 'Возач који у моторном возилу на предњем седишту превози дете млађе од 12 година, казниће се:', 'multipleChoice', NULL, 2, 113),
  ('posledice_0114', 'posledice', 'Возач који у моторном возилу превози дете до три године старости ван безбедносног седишта, односно корпе, казниће се:', 'multipleChoice', NULL, 2, 114),
  ('posledice_0115', 'posledice', 'Возач који се креће саобраћајном траком којом није дозвољено кретање оне врсте возила којим управља, казниће се:', 'multipleChoice', NULL, 2, 115),
  ('posledice_0116', 'posledice', 'Возач који се у насељу креће брзином која је од 11 km/h до 20 km/h већа од дозвољене, казниће се:', 'multipleChoice', NULL, 2, 116),
  ('posledice_0117', 'posledice', 'Ако се у ситуацији приказаној на слици, након саобраћајног знака, крећете брзином од 110 km/h, бићете кажњени:', 'multipleChoice', 'posledice_0117.png', 1, 117),
  ('posledice_0118', 'posledice', 'пролаз, уђе у раскрсницу тако да се због густине саобраћаја заустави у раскрсници и тиме заустави саобраћај, казниће се:', 'multipleChoice', NULL, 2, 118),
  ('posledice_0119', 'posledice', 'Возач који претиче друго возило преко прелаза пута преко железничке пруге, казниће се:', 'multipleChoice', NULL, 2, 119),
  ('posledice_0120', 'posledice', 'Возач који на јавном путу на коме се саобраћај одвија у оба смера паркира возило непосредно уз леву ивицу коловоза, казниће се:', 'multipleChoice', NULL, 2, 120),
  ('posledice_0121', 'posledice', 'Возач који паркира возило на пешачком прелазу, казниће се:', 'multipleChoice', NULL, 2, 121),
  ('posledice_0122', 'posledice', 'Возач који паркира возило на раскрсници, казниће се:', 'multipleChoice', NULL, 1, 122),
  ('posledice_0123', 'posledice', 'Возач који паркира возило на делу пута где је ширина слободног пролаза од паркираног возила до неиспрекидане уздужне линије на коловозу, мања од три метра, казниће се:', 'multipleChoice', NULL, 2, 123),
  ('posledice_0124', 'posledice', 'Возач који паркира возило на стајалишту за возила јавног саобраћаја, казниће се:', 'multipleChoice', NULL, 2, 124),
  ('posledice_0125', 'posledice', 'Возач који паркира возило на месту на коме онемогућaва излазак неком већ паркираном возилу, казниће се:', 'multipleChoice', NULL, 2, 125),
  ('posledice_0126', 'posledice', 'Возач који паркира возило на тротоару, када то није дозвољено саобраћајном сигнализацијом, казниће се:', 'multipleChoice', NULL, 1, 126),
  ('posledice_0127', 'posledice', 'које је заустављено на коловозу на таквом месту да возачи возила која се крећу истим смером не могу благовремено да га уоче, казниће се:', 'multipleChoice', NULL, 2, 127),
  ('posledice_0128', 'posledice', 'Возач који управља трактором у саобраћају на путу који вуче прикључно возило које није прикључно возило за трактор, казниће се:', 'multipleChoice', NULL, 2, 128) ON CONFLICT (id) DO NOTHING;
