  ('posledice_0131', 'posledice', 'Возач возила које вуче неисправно возило, када не постави на оба возила сигурносни троугао на прописан начин, казниће се:', 'multipleChoice', NULL, 2, 131),
  ('posledice_0132', 'posledice', 'Возач возила који користи дуга светла на путу са осветљеном уличном расветом, казниће се:', 'multipleChoice', NULL, 2, 132),
  ('posledice_0133', 'posledice', 'Возач возила који за време магле користи дуга светла, казниће се:', 'multipleChoice', NULL, 2, 133),
  ('posledice_0134', 'posledice', 'Возач мопеда, односно мотоцикла, који за време вожње не носи на глави закопчану хомологовану заштитну кацигу, казниће се:', 'multipleChoice', NULL, 2, 134),
  ('posledice_0135', 'posledice', 'Возач који када скреће на бочни пут на чијем улазу не постоји пешачки прелаз не пропусти пешака који ступа на коловоз, казниће се:', 'multipleChoice', NULL, 2, 135),
  ('posledice_0136', 'posledice', 'Возач који на аутопуту не користи крајњу десну саобраћајну траку, осим приликом претицања, казниће се:', 'multipleChoice', NULL, 2, 136),
  ('posledice_0137', 'posledice', 'Возач трактора који на возилу ноћу нема укључено жуто ротационо или трепћуће светло, казниће се:', 'multipleChoice', NULL, 2, 137),
  ('posledice_0138', 'posledice', 'Возач који управља теретним возилом на којем терет у расутом стању није прекривен, казниће се:', 'multipleChoice', NULL, 2, 138),
  ('posledice_0139', 'posledice', 'Возач возила на којем терет прелази најудаљенију тачку на задњој страни возила, није означен, казниће се:', 'multipleChoice', NULL, 2, 139),
  ('posledice_0140', 'posledice', 'Возач који управља трактором који вуче прикључно возило за трактор у којем се превози више од пет лица, казниће се:', 'multipleChoice', NULL, 2, 140),
  ('posledice_0141', 'posledice', 'Возач који поступи супротно постављеном саобраћајном знаку, казниће се:', 'multipleChoice', NULL, 2, 141),
