  ('posebne_mere_0048', 'posebne_mere', 'Ванредни технички преглед возила, које је искључено из саобраћаја због техничке неисправности утврђене на контролном техничком прегледу, се обавља:', 'multipleChoice', NULL, 2, 48),
  ('posebne_mere_0049', 'posebne_mere', 'Ванредни технички преглед возила, које је искључено из саобраћаја због техничке неисправности утврђене на контролном техничком прегледу се:', 'multipleChoice', NULL, 2, 49),
