  ('posebne_mere_0057', 'posebne_mere', 'Када се путем видео надзора или фото записа утврди да је возило паркирано супротно прописима биће донето решење у електронској форми којим се налаже уклањање возила:', 'multipleChoice', NULL, 2, 57),
