  ('pravila_saobracaja_0064', 'може нагло смањити брзину ради пропуштања сивог возила и након тога скренути удесно.', FALSE, 2),
  ('pravila_saobracaja_0065', 'нагло смањивање брзине и скретање удесно је дозвољено, јер постоји простор за извођење жељене радње,', FALSE, 0),
