  ('pravila_saobracaja_0065', 'нагло смањивање брзине је дозвољено, а да би скренуо удесно мора се уверити да радњу може извршити на безбедан начин.', FALSE, 2),
  ('pravila_saobracaja_0066', 'да отпочне такву радњу само ако се уверио да то може да учини на безбедан начин и дао прописан знак показивачем правца,', FALSE, 0),
  ('pravila_saobracaja_0066', 'увек да отпочне такву радњу уколико се уверио да је та радња у складу са саобраћајном сигнализацијом,', FALSE, 1),
  ('pravila_saobracaja_0066', 'увек да отпочне такву радњу, ако је дао прописан знак показивачем правца.', FALSE, 2),
  ('pravila_saobracaja_0067', 'на прописан начин јер је дао десни показивач правца,', FALSE, 0),
  ('pravila_saobracaja_0067', 'на непрописан начин јер се пре укључивања десног показивача правца није уверио да то може извршити на безбедан начин,', FALSE, 1),
  ('pravila_saobracaja_0067', 'на прописан начин јер сте дужни да пропустите возило које се са паркинг места укључује саобраћај. 2 ПОСЛОВА−УПРАВА 8', FALSE, 2),
  ('pravila_saobracaja_0068', 'може одмах започети извођење те радње, без давања знака показивачем правца, јер се уверио да радњу може извршити на безбедан начин,', FALSE, 0),
  ('pravila_saobracaja_0068', 'мора друге учеснике у саобраћају јасно и благовремено да обавести о томе, дајући им знак показивачем правца,', FALSE, 1),
  ('pravila_saobracaja_0068', 'може одмах започети извођење те радње, а знак показивачем правца ће дати истовремено са започињањем те радње.', FALSE, 2),
  ('pravila_saobracaja_0069', 'само на почетку извођења радње', FALSE, 0),
  ('pravila_saobracaja_0069', 'само док се не увери да су други учесници у саобраћају схватили његову намеру,', FALSE, 1),
  ('pravila_saobracaja_0069', 'за све време вршења радње возилом, а по извршеној радњи мора престати са давањем тог знака.', FALSE, 2),
  ('pravila_saobracaja_0070', 'мора прво дати знак показивачем правца и затим се уверити да може да отпочне вршење радње,', FALSE, 0),
  ('pravila_saobracaja_0070', 'се мора прво уверити да може да отпочне вршење радње и затим дати знак показивачем правца,', FALSE, 1),
  ('pravila_saobracaja_0070', 'даје знак показивачем правца док се уверава да може да отпочне вршење радње.', FALSE, 2),
