  ('pravila_saobracaja_0072', 'уз помоћ лица које се налази возилу има бољу прегледност.', FALSE, 2),
  ('pravila_saobracaja_0073', 'нисте дужни да омогућите укључивање, али ћете то учинити с обзиром да сте на време уочили његову намеру, јер ћете на тај начин избећи настанак опасне ситуације уколико возач настави започету радњу,', FALSE, 0),
  ('pravila_saobracaja_0073', 'дужни сте да омогућите укључивање, јер морате пропустити возило које је започело радњу укључивања у саобраћај,', FALSE, 1),
  ('pravila_saobracaja_0073', 'дужни сте да омогућите укључивање возила јер се ради о возилу за јавни превоз путника.', FALSE, 2),
  ('pravila_saobracaja_0074', 'укључите леви показивач правца и укључите се у саобраћај,', FALSE, 0),
  ('pravila_saobracaja_0074', 'укључите леви показивач правца, омогућите да вас обиђе возило које сте уочили у возачким огледалима и укључите се у саобраћај,', FALSE, 1),
  ('pravila_saobracaja_0074', 'сачекате да вас возило које се креће иза вас обиђе, укључите леви показивач правца и укључите се у саобраћај.', FALSE, 2),
  ('pravila_saobracaja_0075', 'постепено помера возило, у циљу уочавања његовог возила од осталих учесника у саобраћају и да заузме положај тела на седишту који му омогућава потребну прегледност,', FALSE, 0),
