  ('pravila_saobracaja_0168', 'са своје леве стране остави довољно растојање између свог возила и возила са којим се мимоилази,', FALSE, 0),
  ('pravila_saobracaja_0168', 'са своје леве стране остави најмање 0,5 m растојања између свог возила и разделне линије,', FALSE, 1),
