  ('pravila_saobracaja_0168', 'са своје леве стране остави најмање 1 m растојања између свог возила и возила са којим се мимоилази.', FALSE, 3),
  ('pravila_saobracaja_0169', 'остави најмање 1 m растојања између свог возила и пешака са којим се мимоилази,', FALSE, 0),
  ('pravila_saobracaja_0169', 'звучним знаком упозорења обавести пешака о свом присуству како би се пешак померио на безбедно растојање,', FALSE, 1),
  ('pravila_saobracaja_0169', 'држи безбедно растојање између возила и пешака. 2 Уколико због препреке на путу, која се налази у', FALSE, 2),
  ('pravila_saobracaja_0170', 'да успори кретање свог возила, да би пропустио возилa из супротног смера,', FALSE, 0),
  ('pravila_saobracaja_0170', 'настави кретање обилажењем препреке, јер има првенство пролаза у односу на возила из супротног смера,', FALSE, 1),
