  ('pravila_saobracaja_0171', 'дужни сте да успорите кретање свог возила и да га, по потреби, зауставите да би пропустили само прво возило из супротног смера,', FALSE, 0),
  ('pravila_saobracaja_0171', 'дужни сте да успорите кретање свог возила и да га,по потреби, зауставите да би пропустили возила из супротног смера,', FALSE, 1),
  ('pravila_saobracaja_0171', 'наставићете кретање обилажењем препреке, јер имате првенство пролаза у односу на возила из супротног смера.', FALSE, 2),
  ('pravila_saobracaja_0172', 'остави са десне стране свог возила најмање 0,5 m растојања до паркираних возила,', FALSE, 0),
  ('pravila_saobracaja_0172', 'возило помери ка десној ивици коловоза и остави са своје леве стране довољно растојање између свог и Вашег возила', FALSE, 1),
  ('pravila_saobracaja_0172', 'остави са своје леве стране најмање 1 m растојања између свог и вашег возила.', FALSE, 2),
  ('pravila_saobracaja_0173', 'успорићете и оставићете са своје леве стране довољно растојање између свог возила и возила са којим се мимоилазите, а по потреби и зауставити возило да би пропустили возило које вам долази у сусрет,', FALSE, 0),
  ('pravila_saobracaja_0173', 'оставићете са своје десне стране најмање 0,5 m растојања између свог возила и ивице коловоза,', FALSE, 1),
  ('pravila_saobracaja_0173', 'возило ћете померити ка десној ивици коловоза и по потреби се делимично кретати по тротоару.', FALSE, 2),
  ('pravila_saobracaja_0174', 'успорите кретање свог возила и да га, по потреби, зауставите и пропустите возило које Вам долази у сусрет,', FALSE, 0),
  ('pravila_saobracaja_0174', 'наставите кретање јер имате предност у односу на возача возила које Вам долази у сусрет, а возач другог возила је дужан да кретањем уназад или на други начин, помери своје возило и заузме на путу положај који омогућава мимоилажење,', FALSE, 1),
  ('pravila_saobracaja_0174', 'наставите кретање коришћењем потребне површине тротоара омогућите мимоилажење. 2 ПОСЛОВА−УПРАВА 22', FALSE, 2),
  ('pravila_saobracaja_0175', 'дужни сте да успорите кретање свог возила и да га, по потреби, зауставите и пропустите возило које Вам долази у сусрет,', FALSE, 0),
  ('pravila_saobracaja_0175', 'имате предност у односу на возило које Вам долази у сусрет,', FALSE, 1),
  ('pravila_saobracaja_0175', 'дужни сте да успорите кретање свог возила и да га, по потреби, зауставите да би пропустили само прво возило из супротног смера.', FALSE, 2),
  ('pravila_saobracaja_0176', 'дужан је да се заустави возач коме је то, с обзиром на карактеристике и стање пута и саобраћајну ситуацију, лакше да изведе,', FALSE, 0),
  ('pravila_saobracaja_0176', 'дужан је да се заустави возач који са десне стране нема банкину или тротоар чија површина би омогућила кретање ради мимоилажења,', FALSE, 1),
  ('pravila_saobracaja_0176', 'возач којем је то, с обзиром на карактеристике и стање пута и саобраћајну ситуацију, лакше да изведе, дужан је да по потреби, кретањем уназад или на други начин, помери своје возило и заузме на путу положај који омогућава мимоилажење,', FALSE, 2),
  ('pravila_saobracaja_0176', 'возила могу наставити кретање уколико ширина банкине или тротоара омогућава њихово мимоилажење.', FALSE, 3),
  ('pravila_saobracaja_0177', 'леве стране', FALSE, 0),
