  ('pravila_saobracaja_0178', 'леве стране.', FALSE, 2),
  ('pravila_saobracaja_0179', 'возач возила које се креће уз нагиб дужан је да заустави своје возило на погодном месту ако примети да му друго возило иде у сусрет низ нагиб,', FALSE, 0),
  ('pravila_saobracaja_0179', 'возач возила које се креће низ нагиб дужан је да заустави своје возило на погодном месту ако примети да му друго возило иде у сусрет уз нагиб,', FALSE, 1),
  ('pravila_saobracaja_0179', 'возила могу наставити кретање уколико ширина банкине или тротоара омогућава њихово мимоилажење. 2 На делу пута који је саобраћајним знаком означен као', FALSE, 2),
  ('pravila_saobracaja_0180', 'возач возила које се креће уз нагиб дужан је да заустави своје возило ако испред себе има погодно место за заустављање, које омогућава безбедно мимоилажење,', FALSE, 0),
  ('pravila_saobracaja_0180', 'возач возила које се креће уз нагиб нема обавезу заустављања без обзира на постојање места за његово заустављање, јер је возач возила које се креће низ нагиб дужан да омогући мимоилажење,', FALSE, 1),
  ('pravila_saobracaja_0180', 'возила могу наставити кретање коришћењем површине банкине или тротоара, које омогућавају њихово мимоилажење. 2 У ситуацији приказаној на слици, на делу пута који је', FALSE, 2),
  ('pravila_saobracaja_0181', 'возач возила које се креће уз нагиб дужан је да заустави своје возило јер има погодно место за заустављање, које омогућава безбедно мимоилажење,', FALSE, 0),
  ('pravila_saobracaja_0181', 'возач возила које се креће низ нагиб је дужан да се заустави и кретањем уназад до погодног места омогући мимоилажење,', FALSE, 1),
  ('pravila_saobracaja_0181', 'возачи ће се визуелном комуникацијом покретима руком, давањем звучног или светлосног знака упозорења, споразумети о најбезбеднијем начину мимоилажења. 2 ПОСЛОВА−УПРАВА 23', FALSE, 2),
  ('pravila_saobracaja_0182', 'наставићете кретање јер се крећете уз нагиб, а возач возила из супротног смера је дужан да кретањем уназад омогући мимоилажење,', FALSE, 0),
  ('pravila_saobracaja_0182', 'наставићете кретање јер се крећете уз нагиб, а возач возила из супротног смера је дужан да кретањем уназад или кретањем по тротоару омогући мимоилажење,', FALSE, 1),
  ('pravila_saobracaja_0182', 'дужни сте да зауставите возило на месту које омогућава безбедно мимоилажење. 2 На делу пута који је саобраћајним знаком означен као опасан успон, односно као опасна низбрдица, на коме', FALSE, 2),
  ('pravila_saobracaja_0183', 'свако возило које се сусрело са возилом које вуче прикључно возило,', FALSE, 0),
  ('pravila_saobracaja_0183', 'возило које се креће низ нагиб, без обзира на врсту возила које се креће уз нагиб,', FALSE, 1),
  ('pravila_saobracaja_0183', 'теретно возило које се сусрело са аутобусом', FALSE, 2),
  ('pravila_saobracaja_0183', 'возило које се креће уз нагиб, под условом да у непосредној близини има погодно место које омогућава његово заустављање и мимоилажење возила. 2 На делу пута који је саобраћајним знаком означен као опасан успон, односно као опасна низбрдица, на коме', FALSE, 3),
  ('pravila_saobracaja_0184', 'возило које се креће низ нагиб, без обзира на врсту возила које се креће уз нагиб,', FALSE, 0),
  ('pravila_saobracaja_0184', 'ако се мимоилазе возила исте врсте - возило које се креће низ нагиб, осим ако је, с обзиром на услове и положај возила на путу, лакше да то учини возач возила које се креће уз нагиб,', FALSE, 1),
  ('pravila_saobracaja_0184', 'возило које се креће уз нагиб, под условом да у непосредној близини има погодно место које омогућава његово заустављање и мимоилажење возила,', FALSE, 2),
  ('pravila_saobracaja_0184', 'возило које се сусрело са возилом више врсте.', FALSE, 3),
