  ('pravila_saobracaja_0185', 'скуп возила, аутобус, теретно возило, радна машина, трактор, путничко возило и врста коју чине мотоцикл, мопед, трицикл и четвороцикл,', FALSE, 1),
  ('pravila_saobracaja_0185', 'скуп возила, радна машина, трактор, теретно возило, аутобус, путничко возило и врста коју чине мотоцикл, мопед, трицикл и четвороцикл. 2 У ситуацији приказаној на слици, на делу пута који је', FALSE, 2),
  ('pravila_saobracaja_0186', 'возач путничког возила дужан је да кретањем уназад до погодног места омогући мимоилажење,', FALSE, 0),
