  ('pravila_saobracaja_0187', 'возачи ће се визуелном комуникацијом покретима руком, давањем звучног или светлосног знака упозорења, споразумети ко ће се кретати уназад да би се мимоишли. 2 ПОСЛОВА−УПРАВА 24', FALSE, 2),
  ('pravila_saobracaja_0188', 'возачи ће се визуелном комуникацијом покретима руком, давањем звучног или светлосног знака упозорења, споразумети ко ће се кретати уназад да би се мимоишли,', FALSE, 0),
