  ('vozaci_0103', 'породицу повређеног лица. 2 Возач који је учествовао у саобраћајној незгоди у којој', FALSE, 2),
  ('vozaci_0104', 'обавести полицију и попуни Европски извештај о саобраћајној незгоди,', FALSE, 0),
  ('vozaci_0104', 'обезбеди трагове и предмете незгоде, под условом да тиме не угрожава безбедност саобраћаја,', FALSE, 1),
  ('vozaci_0104', 'обавести службу помоћи на путу и удаљи се са места незгоде ако прети опасност од нових саобраћајних незгода.', FALSE, 2),
  ('vozaci_0105', 'обавести службу хитне помоћи и удаљи се са места незгоде ако прети опасност од нових саобраћајних незгода,', FALSE, 0),
  ('vozaci_0105', 'обавести службу хитне помоћи, повређене што пре уклони са коловоза, односно избави из возила и остави их на месту где не могу бити угрожени,', FALSE, 1),
  ('vozaci_0105', 'укаже помоћ повређенима, односно прву помоћ или медицинску помоћ у складу са својим знањима, способностима и могућностима.', FALSE, 2),
  ('vozaci_0106', 'није обавезно да предузима било какве радње односно мора обићи место саобраћајне незгоде на начин који неће довести до уништења трагова уколико је то могуће,', FALSE, 0),
  ('vozaci_0106', 'обавезно је да у складу са својим знањима способностима и могућностима пружи помоћ лицима повређеним у саобраћајној незгоди и по потреби их превезе до најближе здравствене установе,', FALSE, 1),
  ('vozaci_0106', 'обавезно је да се што пре удаљи са места саобраћајне незгоде и обавести најближу службу помоћи на путу,', FALSE, 2),
  ('vozaci_0106', 'обавезно је да предузме све што је у његовој моћи да спречи увећавање постојећих, односно настајање нових последица. 2 Возач је дужан да заустави возило, искључи мотор, укључи све показиваче правца, постави сигурносни', FALSE, 3),
  ('vozaci_0107', 'када је учествовао у саобраћајној незгоди без обзира на њене последице,', FALSE, 0),
  ('vozaci_0107', 'када је учествовао у саобраћајној незгоди у којој је неко лице задобило телесне повреде, односно погинуло, или је настала велика материјална штета,', FALSE, 1),
  ('vozaci_0107', 'када учесник који је изазвао саобраћајну незгоду неће да надокнади малу материјалну штету која је наступила као последица те незгоде.', FALSE, 2),
  ('vozaci_0108', 'није дозвољено', FALSE, 0),
  ('vozaci_0108', 'је дозвољено, након спроведеног испитивања на присуство ових материја,', FALSE, 1),
  ('vozaci_0108', 'није дозвољено, само када му такву забрану саопшти лице које врши увиђај. 2 ПОСЛОВА−УПРАВА 9', FALSE, 2),
  ('vozaci_0109', 'предузме све мере заштите које су у његовој моћи да се спречи настајање нових и увећавање постојећих последица и повреда,', FALSE, 0),
  ('vozaci_0109', 'обавести службу помоћи на путу и удаљи се са места незгоде ако прети опасност од нових саобраћајних незгода,', FALSE, 1),
  ('vozaci_0109', 'обавести полицију и удаљи се са места незгоде ако није изазвао ту незгоду и нема знања, способности и могућности да пружи помоћ лицима повређеним у саобраћајној незгоди.', FALSE, 2),
  ('vozaci_0110', 'дужан је да до доласка полиције врши регулисање саобраћаја на начин како то раде овлашћена лица,', FALSE, 0),
  ('vozaci_0110', 'дужан је да упозори сва лица да се склоне са коловоза да не би била повређена и да не би уништавала трагове незгоде,', FALSE, 1),
  ('vozaci_0110', 'није дужан да даје упозорења лицима која се затекну или наиђу на место саобраћајне незгоде. 2 Возач који је учествовао у саобраћајној незгоди у којој', FALSE, 2),
  ('vozaci_0111', 'обавести службу помоћи на путу и да се удаљи са места незгоде ако прети опасност од нових саобраћајних незгода,', FALSE, 0),
  ('vozaci_0111', 'обавести полицију и да се удаљи са места незгоде ако није изазвао ту незгоду и нема знања, способности и могућности да пружи помоћ лицима повређеним у саобраћајној незгоди,', FALSE, 1),
  ('vozaci_0111', 'обавести полицију и остане на месту незгоде до доласка полиције и завршетка увиђаја. 2 Возач који је учествовао у саобраћајној незгоди у којој', FALSE, 2),
  ('vozaci_0112', 'дужан је да остане на месту незгоде до доласка полиције, без обзира на своје и повреде других учесника незгоде,', FALSE, 0),
  ('vozaci_0112', 'може се удаљити са места незгоде ако му је неопходна хитна медицинска помоћ,', FALSE, 1),
  ('vozaci_0112', 'може се удаљити са места незгоде ради превожења повређеног до најближе здравствене установе,', FALSE, 2),
  ('vozaci_0112', 'може се удаљити са места незгоде ако нема знања, способности и могућности да пружи помоћ лицима повређеним у саобраћајној незгоди.', FALSE, 3),
  ('vozaci_0113', 'може захтевати да полицијски службеник изађе на место незгоде и изврши увиђај,', FALSE, 0),
  ('vozaci_0113', 'не може захтевати да полицијски службеник изађе на место незгоде и изврши увиђај, односно учесници ће попунити Европски извештај о саобраћајној незгоди,', FALSE, 1),
  ('vozaci_0113', 'може захтевати да полицијски службеник изађе на место незгоде и изврши увиђај, само у случају када су и остали учесници, односно лице које је претрпело материјалну штету, сагласни са тим захтевом. 2 Ако је бар један учесник или лице које је претрпело', FALSE, 2),
  ('vozaci_0114', 'нису дужни да остану на месту саобраћајне незгоде, до завршетка увиђаја,', FALSE, 0),
  ('vozaci_0114', 'су дужни да оставе податке о себи и возилу учеснику који је захтевао вршење увиђаја и могу се удаљити са места саобраћајне незгоде,', FALSE, 1),
  ('vozaci_0114', 'су дужни да остану на месту саобраћајне незгоде, до завршетка увиђаја.', FALSE, 2),
  ('vozaci_0115', 'дужан је да до доласка полиције врши регулисање саобраћаја на начин како то раде овлашћена лица,', FALSE, 0),
  ('vozaci_0115', 'дужан је да упозори остале учеснике у саобраћају о постојању возила и других препрека на путу, уколико их сам не може уклонити,', FALSE, 1),
  ('vozaci_0115', 'дужан је да уклони возило и друге предмете са коловоза, ако онемогућавају или угрожавају одвијање саобраћаја, односно ако прети опасност од нових саобраћајних незгода,', FALSE, 2),
  ('vozaci_0115', 'није дужан да даје упозорења лицима која се затекну или наиђу на место саобраћајне незгоде,', FALSE, 3),
  ('vozaci_0115', 'не сме померати возило са места саобраћајне незгоде. 2 Узимање узорка крви, односно урина, ради утврђивања', FALSE, 4),
  ('vozaci_0116', 'је обавезно', FALSE, 0),
  ('vozaci_0116', 'није обавезно, уколико је провера присуства ових материја извршена коришћењем одговарајућих средстава,', FALSE, 1),
  ('vozaci_0116', 'је обавезно, само у случају када је присуство ових материја утврђено коришћењем одговарајућих средстава. 2 ПОСЛОВА−УПРАВА 10', FALSE, 2),
  ('vozaci_0117', 'дужан је да попуни Европски извештај о саобраћајној незгоди у случају када овлашћено лице не врши увиђај саобраћајне незгоде,', FALSE, 0),
