  ('vozaci_0118', 'дужан је да предузме мере заштите које су у његовој моћи да се спречи настајање нових и увећавање постојећих последица незгоде,', FALSE, 3),
  ('vozaci_0118', 'дужан је да одмах надокнади штету другим учесницима саобраћајне незгоде ако је изазвао ту незгоду. 2 Ако учесник у саобраћајној незгоди у којој је настала', FALSE, 4),
